const mongoose = require('mongoose');
const bcrypt = require('bcrypt');

// Coupon model
const couponSchema = new mongoose.Schema({
  code: String,
  discount: Number,
  expiresAt: Date,
  used: Boolean
});

couponSchema.pre('save', function(next) {
  const now = new Date();
  if (this.expiresAt < now) {
    return next(new Error('Coupon has expired'));
  }
  next();
});

